SourceCode.Declaration:
/// <summary>
/// Extension for InventJournalName datasource on the form.
/// Controls visibility of ETGProductionConsumption field
/// based on Journal Type.
/// </summary>
[ExtensionOf(formDataSourceStr(InventJournalName,InventJournalName))]
final class ETGInventJournalName_DS_Extension
{
}

Method.Source:
public int active()
{
    int ret = next active();

    InventJournalName journalName          = this.cursor();
    boolean           isAutoPostEnabled    = ETGCanadaParameters::find().EnableAutoMovementJournalCreation;
    FormRun           formRun              = this.formRun();
    FormDataObject    prodConsumptionCtrl  = this.object(fieldNum(InventJournalName, ETGProductionConsumption));

    if (prodConsumptionCtrl)
    {
        prodConsumptionCtrl.visible(journalName.JournalType == InventJournalType::Movement && isAutoPostEnabled);
    }

    return ret;
}
